import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./LoginPage.css";

const LoginPage: React.FC = () => {
    const [username, setUsername] = useState("");
    const [password, setPassword] = useState("");
    const navigate = useNavigate();

    const handleLogin = () => {
        // Geliştirme aşamasında herhangi bir kullanıcı adı ve şifreyle giriş yapılabilir
        if (username.trim() && password.trim()) {
            navigate("/dashboard"); // Kullanıcı giriş yaptıktan sonra yönlendirme
        } else {
            alert("Please enter username and password!");
        }
    };

    return (
        <div className="login-container">
            <h2>Login</h2>
            <input
                type="text"
                placeholder="Username"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
            />
            <input
                type="password"
                placeholder="Password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
            />
            <button onClick={handleLogin}>Login</button>

            {/* Şifreyi Unuttum Linki */}
            <a href="#" className="forgot-password">Forgot my password?</a>

            {/* Google ile Giriş Butonu */}
            <button className="google-login">
                <img
                    src="https://upload.wikimedia.org/wikipedia/commons/thumb/5/53/Google_%22G%22_Logo.svg/512px-Google_%22G%22_Logo.svg.png"
                    alt="Google"
                    className="google-icon"
                />
                Sign in with Google
            </button>
        </div>
    );
};

export default LoginPage;
